def parse_log_line(line):
    """
    解析单行日志，提取关键信息

    Args:
        line: 日志行字符串

    Returns:
        dict: 包含解析后的数据
    """
    # 提取时间戳
    timestamp_match = re.search(r"(\d{4}/\d{2}/\d{2} \d{2}:\d{2}:\d{2})", line)
    timestamp = timestamp_match.group(1) if timestamp_match else ""

    # 提取 url_path
    url_path_match = re.search(r'"url_path":"([^"]+)"', line)
    url_path = url_path_match.group(1) if url_path_match else ""

    # 提取 domain
    domain_match = re.search(r'"domain":"([^"]+)"', line)
    domain = domain_match.group(1) if domain_match else ""

    # 提取 dst_domain
    dst_domain_match = re.search(r'"dst_domain":"([^"]+)"', line)
    dst_domain = dst_domain_match.group(1) if dst_domain_match else ""

    # 提取 src_request
    src_request_match = re.search(
        r'"src_request":"(.*?)","dst_request"', line, re.DOTALL
    )
    src_request = src_request_match.group(1) if src_request_match else ""

    # 提取 dst_request
    dst_request_match = re.search(
        r'"dst_request":"(.*?)","src_response"', line, re.DOTALL
    )
    dst_request = dst_request_match.group(1) if dst_request_match else ""

    # 提取 src_response - 在 src_response" 和 ",dst_response" 之间
    src_response_match = re.search(
        r'"src_response":"(.*?)","dst_response"', line, re.DOTALL
    )
    src_response = src_response_match.group(1) if src_response_match else ""

    # 提取 dst_response - 在 dst_response" 和 ","is_replay" 之间
    dst_response_match = re.search(
        r'"dst_response":"(.*?)","is_replay"', line, re.DOTALL
    )
    dst_response = dst_response_match.group(1) if dst_response_match else ""

    return {
        "timestamp": timestamp,
        "url_path": url_path,
        "domain": domain,
        "dst_domain": dst_domain,
        "src_request": src_request,
        "dst_request": dst_request,
        "src_response": src_response,
        "dst_response": dst_response,
    }


def format_json_string(json_str):
    """
    尝试格式化 JSON 字符串

    Args:
        json_str: 可能包含转义的 JSON 字符串

    Returns:
        格式化后的 JSON 对象或原始字符串
    """
    if not json_str:
        return None

    # 处理转义字符
    unescaped = json_str.replace("\\n", "\n").replace('\\"', '"').replace("\\\\", "\\")

    try:
        return json.loads(unescaped)
    except json.JSONDecodeError:
        return unescaped


def process_log_file(input_file, output_file=None):
    """
    处理日志文件

    Args:
        input_file: 输入日志文件路径
        output_file: 输出文件路径（可选）
    """
    results = []

    with open(input_file, "r", encoding="utf-8") as f:
        for line_num, line in enumerate(f, 1):
            line = line.strip()
            if not line:
                continue

            parsed = parse_log_line(line)

            # 格式化 JSON
            parsed["src_response_parsed"] = format_json_string(parsed["src_response"])
            parsed["dst_response_parsed"] = format_json_string(parsed["dst_response"])

            results.append(
                {
                    "line_number": line_num,
                    "timestamp": parsed["timestamp"],
                    "url_path": parsed["url_path"],
                    "domain": parsed["domain"],
                    "dst_domain": parsed["dst_domain"],
                    "src_response": parsed["src_response_parsed"],
                    "dst_response": parsed["dst_response_parsed"],
                }
            )

    # 输出结果
    if output_file:
        with open(output_file, "w", encoding="utf-8") as f:
            json.dump(results, f, ensure_ascii=False, indent=2)
        print(f"结果已写入: {output_file}")
    else:
        print(json.dumps(results, ensure_ascii=False, indent=2))

    # 打印统计信息
    print(f"\n总共解析了 {len(results)} 条记录")

    if results:
        print("\nURL Path 统计:")
        url_counts = {}
        for r in results:
            url_path = r["url_path"] or "UNKNOWN"
            url_counts[url_path] = url_counts.get(url_path, 0) + 1
        for url, count in sorted(url_counts.items(), key=lambda x: x[1], reverse=True):
            print(f"  {url}: {count}")


def main():
    if len(sys.argv) < 2:
        print("用法: python parse_log.py <日志文件> [输出文件]")
        print("\n示例:")
        print("  python parse_log.py log.txt")
        print("  python parse_log.py log.txt output.json")
        sys.exit(1)

    input_file = sys.argv[1]
    output_file = sys.argv[2] if len(sys.argv) > 2 else None

    if not Path(input_file).exists():
        print(f"错误: 文件 '{input_file}' 不存在")
        sys.exit(1)

    process_log_file(input_file, output_file)


if __name__ == "__main__":
    main()
